SELECT o.id, o.order_no, o.title, o.amount, o.status, o.create_time FROM orders o WHERE o.customer_id = #{customerId}
AND o.status = #{status}
ORDER BY o.create_time ASC ORDER BY o.create_time DESC

SELECT o.id, o.order_no, o.title, o.amount, o.status, o.create_time FROM orders o WHERE o.runner_id = #{runnerId}
AND o.status = #{status}
ORDER BY o.create_time ASC ORDER BY o.create_time DESC
